+            GateDecision::Open => {
+                let mut storage = self.storage.write().unwrap();
+                mutator(&mut storage);
+                self.gate.coherence.store(predicted_coherence, Ordering::Release);
+                Ok(())
+            }
+            decision => Err(decision),
+        }
+    }
